create table recruitment_jobs (job_id varchar(36) not null, tenant_code varchar(64) not null, title varchar(200) not null, department varchar(120) null, location varchar(120) null, status varchar(30) not null, created_at timestamp not null, updated_at timestamp not null, created_by varchar(120) not null, updated_by varchar(120) not null, primary key (job_id));
create table recruitment_candidates (candidate_id varchar(36) not null, tenant_code varchar(64) not null, job_id varchar(36) not null, full_name varchar(180) not null, email varchar(180) null, phone varchar(40) null, stage varchar(30) not null, created_at timestamp not null, updated_at timestamp not null, created_by varchar(120) not null, updated_by varchar(120) not null, primary key (candidate_id));
create table recruitment_candidate_stage_history (history_id varchar(36) not null, tenant_code varchar(64) not null, candidate_id varchar(36) not null, from_stage varchar(30) null, to_stage varchar(30) not null, comment varchar(500) null, created_at timestamp not null, updated_at timestamp not null, created_by varchar(120) not null, updated_by varchar(120) not null, primary key (history_id));
create index idx_recruitment_jobs_tenant on recruitment_jobs (tenant_code);
create index idx_recruitment_candidates_tenant on recruitment_candidates (tenant_code);
create index idx_recruitment_history_tenant_candidate on recruitment_candidate_stage_history (tenant_code, candidate_id);
